package entities;

import java.time.LocalDateTime;
import java.util.ArrayList;
import java.util.List;

public class Musique {
    private Integer id;
    private String genre;
    private String audio;
    private LocalDateTime updatedAt;

    // Relation many-to-many via playlist_musique (loaded by service layer).
    private List<Playlist> playlists = new ArrayList<>();

    public Musique() {
    }

    public Integer getId() {
        return id;
    }

    public void setId(Integer id) {
        this.id = id;
    }

    public String getGenre() {
        return genre;
    }

    public void setGenre(String genre) {
        this.genre = genre;
    }

    public String getAudio() {
        return audio;
    }

    public void setAudio(String audio) {
        this.audio = audio;
    }

    public LocalDateTime getUpdatedAt() {
        return updatedAt;
    }

    public void setUpdatedAt(LocalDateTime updatedAt) {
        this.updatedAt = updatedAt;
    }

    public List<Playlist> getPlaylists() {
        return playlists;
    }

    public void setPlaylists(List<Playlist> playlists) {
        this.playlists = playlists != null ? playlists : new ArrayList<>();
    }
}

package entities;

import java.time.LocalDateTime;
import java.util.ArrayList;
import java.util.List;

public class Musique extends Oeuvre {
    private String genre;
    private String audio;
    private LocalDateTime updatedAt;

    // Relation many-to-many via playlist_musique (loaded by service layer).
    private List<Playlist> playlists = new ArrayList<>();

    public Musique() {
        super();
        setClasse("musique");
    }

    public String getGenre() {
        return genre;
    }

    public void setGenre(String genre) {
        this.genre = genre;
    }

    public String getAudio() {
        return audio;
    }

    public void setAudio(String audio) {
        this.audio = audio;
    }

    public LocalDateTime getUpdatedAt() {
        return updatedAt;
    }

    public void setUpdatedAt(LocalDateTime updatedAt) {
        this.updatedAt = updatedAt;
    }

    public List<Playlist> getPlaylists() {
        return playlists;
    }

    public void setPlaylists(List<Playlist> playlists) {
        this.playlists = playlists != null ? playlists : new ArrayList<>();
    }
}

package entities;

import java.time.LocalDate;
import java.time.LocalDateTime;

public class Personne {
    private Integer id;
    private String photoProfil;
    private String resetToken;
    private LocalDateTime resetTokenExpires;
    private String nom;
    private String prenom;
    private LocalDate dateNaissance;
    private String email;
    private String mdp;
    private String role;
    private String statut;
    private LocalDate dateInscription;
    private String numTel;
    private String ville;
    private String biographie;
    private String specialite;
    private String centreInteret;
    private String photoReferencePath;

    // Legacy field kept for compatibility with existing ServicePersonne.
    private Integer age;

    public Personne() {
    }

    public Personne(String nom, String prenom, Integer age) {
        this.nom = nom;
        this.prenom = prenom;
        this.age = age;
    }

    public Integer getId() {
        return id;
    }

    public void setId(Integer id) {
        this.id = id;
    }

    public String getPhotoProfil() {
        return photoProfil;
    }

    public void setPhotoProfil(String photoProfil) {
        this.photoProfil = photoProfil;
    }

    public String getResetToken() {
        return resetToken;
    }

    public void setResetToken(String resetToken) {
        this.resetToken = resetToken;
    }

    public LocalDateTime getResetTokenExpires() {
        return resetTokenExpires;
    }

    public void setResetTokenExpires(LocalDateTime resetTokenExpires) {
        this.resetTokenExpires = resetTokenExpires;
    }

    public String getNom() {
        return nom;
    }

    public void setNom(String nom) {
        this.nom = nom;
    }

    public String getPrenom() {
        return prenom;
    }

    public void setPrenom(String prenom) {
        this.prenom = prenom;
    }

    public LocalDate getDateNaissance() {
        return dateNaissance;
    }

    public void setDateNaissance(LocalDate dateNaissance) {
        this.dateNaissance = dateNaissance;
    }

    public String getEmail() {
        return email;
    }

    public void setEmail(String email) {
        this.email = email;
    }

    public String getMdp() {
        return mdp;
    }

    public void setMdp(String mdp) {
        this.mdp = mdp;
    }

    public String getRole() {
        return role;
    }

    public void setRole(String role) {
        this.role = role;
    }

    public String getStatut() {
        return statut;
    }

    public void setStatut(String statut) {
        this.statut = statut;
    }

    public LocalDate getDateInscription() {
        return dateInscription;
    }

    public void setDateInscription(LocalDate dateInscription) {
        this.dateInscription = dateInscription;
    }

    public String getNumTel() {
        return numTel;
    }

    public void setNumTel(String numTel) {
        this.numTel = numTel;
    }

    public String getVille() {
        return ville;
    }

    public void setVille(String ville) {
        this.ville = ville;
    }

    public String getBiographie() {
        return biographie;
    }

    public void setBiographie(String biographie) {
        this.biographie = biographie;
    }

    public String getSpecialite() {
        return specialite;
    }

    public void setSpecialite(String specialite) {
        this.specialite = specialite;
    }

    public String getCentreInteret() {
        return centreInteret;
    }

    public void setCentreInteret(String centreInteret) {
        this.centreInteret = centreInteret;
    }

    public String getPhotoReferencePath() {
        return photoReferencePath;
    }

    public void setPhotoReferencePath(String photoReferencePath) {
        this.photoReferencePath = photoReferencePath;
    }

    public Integer getAge() {
        return age;
    }

    public void setAge(Integer age) {
        this.age = age;
    }

    @Override
    public String toString() {
        return "Personne{" +
                "id=" + id +
                ", nom='" + nom + '\'' +
                ", prenom='" + prenom + '\'' +
                ", email='" + email + '\'' +
                ", role='" + role + '\'' +
                ", statut='" + statut + '\'' +
                '}';
    }
}

.app-root {
    -fx-font-family: "Segoe UI", Arial, sans-serif;
    -fx-background-color: #d2d7df;
}

.sidebar {
    -fx-background-color: #3d3bc2;
    -fx-min-width: 260;
    -fx-pref-width: 260;
    -fx-max-width: 260;
}

.sidebar-brand {
    -fx-padding: 8 10 18 10;
}

.brand-dot {
    -fx-text-fill: #eef0ff;
    -fx-font-size: 24px;
    -fx-font-weight: bold;
}

.brand-label {
    -fx-text-fill: white;
    -fx-font-size: 28px;
    -fx-font-weight: 700;
}

.nav-item,
.nav-sub-item {
    -fx-background-color: transparent;
    -fx-text-fill: #f0f2ff;
    -fx-font-size: 14px;
    -fx-font-weight: 700;
    -fx-alignment: CENTER_LEFT;
    -fx-padding: 9 14 9 14;
    -fx-background-radius: 8;
    -fx-border-radius: 8;
    -fx-cursor: hand;
}

.nav-sub-item {
    -fx-font-size: 13px;
    -fx-font-weight: 600;
    -fx-padding: 8 14 8 26;
}

.sub-menu {
    -fx-padding: 0 0 2 0;
}

.nav-item:hover,
.nav-sub-item:hover {
    -fx-background-color: rgba(255, 255, 255, 0.12);
}

.nav-item.active,
.nav-sub-item.active {
    -fx-background-color: rgba(255, 255, 255, 0.2);
    -fx-text-fill: #ffffff;
}

.sidebar.collapsed .brand-label,
.sidebar.collapsed .sub-menu {
    -fx-opacity: 0;
}

.navbar {
    -fx-background-color: #f8f9fb;
    -fx-border-color: #d9dce3;
    -fx-border-width: 0 0 1 0;
}

.search-field {
    -fx-background-color: #f4f5f7;
    -fx-border-color: #c8cdd7;
    -fx-border-radius: 6;
    -fx-background-radius: 6;
    -fx-padding: 0 10 0 10;
}

.table-search {
    -fx-background-color: #f4f6fa;
    -fx-border-color: #cad2df;
    -fx-border-radius: 10;
    -fx-background-radius: 10;
    -fx-padding: 10 12 10 12;
    -fx-font-size: 14px;
    -fx-margin: 0 0 8 0;
}

.primary-action-button {
    -fx-background-color: #3d3bc2;
    -fx-text-fill: white;
    -fx-font-weight: 700;
    -fx-background-radius: 10;
    -fx-padding: 10 18 10 18;
    -fx-cursor: hand;
}

.primary-action-button:hover {
    -fx-background-color: #3432a8;
}

.icon-button {
    -fx-background-color: #eef1f5;
    -fx-border-color: #d4d9e1;
    -fx-background-radius: 17;
    -fx-border-radius: 17;
    -fx-text-fill: #3b4250;
    -fx-font-weight: 700;
    -fx-cursor: hand;
}

.menu-icon-button {
    -fx-background-color: #eef1f5;
    -fx-border-color: #d4d9e1;
    -fx-background-radius: 16;
    -fx-border-radius: 16;
}

.avatar-menu {
    -fx-background-color: #ebeff5;
    -fx-border-color: #cfd5e0;
    -fx-background-radius: 16;
    -fx-border-radius: 16;
    -fx-text-fill: #243146;
    -fx-font-weight: 700;
}

.content-area {
    -fx-background-color: #d2d7df;
}

.page-root {
    -fx-background-color: #d2d7df;
}

.users-shell {
    -fx-spacing: 18;
}

.users-panel {
    -fx-background-color: white;
    -fx-background-radius: 28;
    -fx-border-color: rgba(225, 232, 241, 0.95);
    -fx-border-radius: 28;
    -fx-effect: dropshadow(gaussian, rgba(34, 47, 63, 0.10), 22, 0.15, 0, 7);
}

.users-title {
    -fx-font-size: 32px;
    -fx-font-weight: 800;
    -fx-text-fill: #1c2b3f;
}

.users-toolbar {
    -fx-alignment: center_left;
}

.users-header {
    -fx-alignment: center_left;
}

.users-header-actions {
    -fx-alignment: center_right;
}

.users-header-chips {
    -fx-alignment: center_right;
}

.panel-chip {
    -fx-background-color: #eef2ff;
    -fx-text-fill: #4252b8;
    -fx-background-radius: 999;
    -fx-padding: 8 14 8 14;
    -fx-font-size: 12px;
    -fx-font-weight: 700;
}

.users-scroll {
    -fx-background: transparent;
    -fx-background-color: transparent;
}

.users-scroll > .viewport {
    -fx-background-color: transparent;
}

.users-cards-container {
    -fx-background-color: linear-gradient(to bottom right, rgba(255,255,255,0.95), rgba(248,250,254,0.95));
    -fx-background-radius: 16;
    -fx-border-color: rgba(210, 219, 231, 0.8);
    -fx-border-radius: 16;
    -fx-padding: 16;
    -fx-effect: dropshadow(gaussian, rgba(34, 47, 63, 0.08), 14, 0, 0, 3);
}

.users-cards-grid {
    -fx-padding: 2 2 4 2;
}

.page-title {
    -fx-font-size: 47px;
    -fx-font-weight: 700;
    -fx-text-fill: #1c2b3f;
}

.page-subtitle {
    -fx-font-size: 19px;
    -fx-text-fill: #314865;
}

.dashboard-scroll {
    -fx-background: #d2d7df;
    -fx-background-color: transparent;
}

.dashboard-scroll > .viewport {
    -fx-background-color: transparent;
}

.dashboard-card {
    -fx-background-color: white;
    -fx-background-radius: 12;
    -fx-border-color: #edf0f4;
    -fx-border-radius: 12;
    -fx-effect: dropshadow(gaussian, rgba(60,60,60,0.08), 10, 0, 0, 2);
    -fx-min-width: 175;
    -fx-pref-width: 190;
    -fx-alignment: CENTER;
}

.dashboard-card:hover {
    -fx-effect: dropshadow(gaussian, rgba(60,60,60,0.15), 16, 0, 0, 4);
}

.icon-circle {
    -fx-background-radius: 20;
    -fx-min-width: 38;
    -fx-min-height: 38;
    -fx-max-width: 38;
    -fx-max-height: 38;
    -fx-alignment: CENTER;
}

.card-icon-text {
    -fx-font-weight: 700;
}

.icon-users {
    -fx-background-color: #e3f2fd;
    -fx-text-fill: #2196f3;
}

.icon-artistes {
    -fx-background-color: #f3e5f5;
    -fx-text-fill: #8e24aa;
}

.icon-amateurs {
    -fx-background-color: #fff3e0;
    -fx-text-fill: #ff9800;
}

.icon-oeuvres {
    -fx-background-color: #e0f7fa;
    -fx-text-fill: #43cea2;
}

.icon-reclam {
    -fx-background-color: #ffebee;
    -fx-text-fill: #e53935;
}

.icon-events {
    -fx-background-color: #e8eaf6;
    -fx-text-fill: #3949ab;
}

.stat-number {
    -fx-font-size: 30px;
    -fx-font-weight: 800;
    -fx-text-fill: #212529;
}

.stat-label {
    -fx-font-size: 14px;
    -fx-text-fill: #6c757d;
}

.list-card {
    -fx-background-color: white;
    -fx-background-radius: 12;
    -fx-border-color: #e8ecf2;
    -fx-border-radius: 12;
    -fx-effect: dropshadow(gaussian, rgba(60,60,60,0.07), 10, 0, 0, 2);
}

.users-panel.list-card {
    -fx-background-color: white;
    -fx-background-radius: 28;
    -fx-border-color: rgba(225, 232, 241, 0.95);
    -fx-border-radius: 28;
    -fx-border-width: 1.2;
    -fx-effect: dropshadow(gaussian, rgba(34, 47, 63, 0.10), 22, 0.15, 0, 7);
}

.user-card {
    -fx-background-color: linear-gradient(to bottom, rgba(255,255,255,0.99), rgba(247,250,255,0.97));
    -fx-background-radius: 18;
    -fx-border-color: #dfe7f2;
    -fx-border-radius: 18;
    -fx-padding: 16;
    -fx-effect: dropshadow(gaussian, rgba(42, 58, 78, 0.10), 16, 0, 0, 5);
    -fx-pref-width: 356;
    -fx-min-height: 248;
}

.user-card:hover {
    -fx-effect: dropshadow(gaussian, rgba(42, 58, 78, 0.16), 22, 0, 0, 7);
    -fx-border-color: #cfd9e8;
}

.user-card-title {
    -fx-font-size: 19px;
    -fx-font-weight: 800;
    -fx-text-fill: #182536;
}

.user-card-subtitle {
    -fx-font-size: 13px;
    -fx-text-fill: #5a6f89;
}

.user-card-text {
    -fx-font-size: 13px;
    -fx-text-fill: #4b627b;
}

.user-card-actions {
    -fx-padding: 10 0 0 0;
}

.user-card-top {
    -fx-alignment: center_left;
}

.user-card-badges {
    -fx-alignment: center_left;
}

.user-card-body {
    -fx-background-color: rgba(240, 245, 252, 0.7);
    -fx-background-radius: 12;
    -fx-padding: 10;
}

.user-avatar {
    -fx-background-color: linear-gradient(to bottom right, #4b6bff, #9b5cff);
    -fx-background-radius: 16;
    -fx-text-fill: white;
    -fx-font-weight: 800;
    -fx-font-size: 14px;
    -fx-alignment: center;
    -fx-min-width: 42;
    -fx-min-height: 42;
    -fx-pref-width: 42;
    -fx-pref-height: 42;
}

.badge-role {
    -fx-background-color: #e9ecff;
    -fx-background-radius: 999;
    -fx-text-fill: #3d3bc2;
    -fx-font-size: 11px;
    -fx-font-weight: 800;
    -fx-padding: 6 10 6 10;
}

.badge-role-secondary {
    -fx-background-color: #eef3ff;
    -fx-background-radius: 999;
    -fx-text-fill: #45608a;
    -fx-font-size: 11px;
    -fx-font-weight: 700;
    -fx-padding: 6 10 6 10;
}

.badge-status {
    -fx-background-color: #edf2fb;
    -fx-background-radius: 999;
    -fx-text-fill: #32445f;
    -fx-font-size: 11px;
    -fx-font-weight: 800;
    -fx-padding: 6 10 6 10;
}

.badge-status.status-active {
    -fx-background-color: #e8faf1;
    -fx-text-fill: #177245;
}

.badge-status.status-pending {
    -fx-background-color: #fff5e6;
    -fx-text-fill: #8d5a19;
}

.badge-status.status-blocked {
    -fx-background-color: #ffeef0;
    -fx-text-fill: #9d3044;
}

.badge-status.status-neutral {
    -fx-background-color: #edf2fb;
    -fx-text-fill: #32445f;
}

.user-info-row {
    -fx-alignment: center_left;
}

.user-info-key {
    -fx-font-size: 12px;
    -fx-font-weight: 700;
    -fx-text-fill: #4f6581;
}

.user-info-value {
    -fx-font-size: 12px;
    -fx-text-fill: #21344d;
}

.card-action-button {
    -fx-background-color: #f0f4fb;
    -fx-border-color: #d8e0eb;
    -fx-background-radius: 11;
    -fx-border-radius: 11;
    -fx-font-size: 12px;
    -fx-font-weight: 700;
    -fx-text-fill: #334760;
    -fx-cursor: hand;
}

.card-soft-button:hover {
    -fx-background-color: #e7eef9;
    -fx-border-color: #c7d2e2;
}

.card-danger-button {
    -fx-background-color: #fff5f5;
    -fx-border-color: #f2c5cb;
    -fx-text-fill: #b03545;
}

.page-message {
    -fx-font-size: 13px;
    -fx-text-fill: #51657d;
}

.users-empty-state {
    -fx-font-size: 14px;
    -fx-font-weight: 700;
    -fx-text-fill: #5b6f89;
    -fx-padding: 24 0 10 4;
}

.page-message.success {
    -fx-text-fill: #258150;
}

.page-message.error {
    -fx-text-fill: #b23a48;
}

.dialog-error {
    -fx-text-fill: #b23a48;
    -fx-font-size: 12px;
}

.users-dialog-pane {
    -fx-background-color: linear-gradient(to bottom, rgba(255, 255, 255, 0.995), rgba(243, 247, 252, 0.985));
    -fx-background-radius: 20;
    -fx-border-color: rgba(210, 221, 235, 0.98);
    -fx-border-radius: 20;
    -fx-effect: dropshadow(gaussian, rgba(26, 38, 58, 0.22), 30, 0.18, 0, 11);
}

.users-dialog-pane > .header-panel {
    -fx-background-color:
        linear-gradient(to right, rgba(61, 59, 194, 0.18), rgba(75, 107, 255, 0.10)),
        linear-gradient(to bottom, rgba(255, 255, 255, 0.12), rgba(255, 255, 255, 0.0));
    -fx-background-radius: 20 20 0 0;
    -fx-padding: 16 18 12 18;
    -fx-border-color: transparent transparent rgba(217, 226, 238, 0.98) transparent;
    -fx-border-width: 0 0 1 0;
}

.users-dialog-pane > .header-panel .label {
    -fx-text-fill: #132035;
    -fx-font-weight: 800;
    -fx-font-size: 16px;
}

.users-dialog-content {
    -fx-padding: 12 14 10 14;
}

.users-dialog-hero {
    -fx-background-color: linear-gradient(to right, rgba(61, 59, 194, 0.12), rgba(75, 107, 255, 0.06));
    -fx-background-radius: 16;
    -fx-padding: 11 14 11 14;
    -fx-border-color: rgba(215, 223, 235, 0.92);
    -fx-border-radius: 16;
}

.users-dialog-scroll {
    -fx-background-color: transparent;
    -fx-background: transparent;
}

.users-dialog-scroll > .viewport {
    -fx-background-color: transparent;
}

.users-dialog-chip-row {
    -fx-alignment: center_left;
}

.users-dialog-mode-chip,
.users-dialog-role-chip,
.users-dialog-status-chip {
    -fx-background-radius: 999;
    -fx-padding: 5 10 5 10;
    -fx-font-size: 11px;
    -fx-font-weight: 800;
}

.users-dialog-mode-chip {
    -fx-background-color: #eef2ff;
    -fx-text-fill: #4252b8;
}

.users-dialog-role-chip {
    -fx-background-color: #edf8ff;
    -fx-text-fill: #2d6ea3;
}

.users-dialog-status-chip {
    -fx-background-color: #f2f5fa;
    -fx-text-fill: #44566f;
}

.users-dialog-title {
    -fx-font-size: 18px;
    -fx-font-weight: 900;
    -fx-text-fill: #16263c;
}

.users-dialog-subtitle {
    -fx-font-size: 11px;
    -fx-text-fill: #5d718a;
}

.users-dialog-section-card {
    -fx-background-color: linear-gradient(to bottom, rgba(255,255,255,0.99), rgba(249,251,254,0.98));
    -fx-background-radius: 14;
    -fx-border-color: rgba(214, 224, 237, 0.96);
    -fx-border-radius: 14;
    -fx-padding: 10 12 12 12;
    -fx-effect: dropshadow(gaussian, rgba(31, 45, 70, 0.07), 10, 0.10, 0, 2);
}

.users-dialog-bio-card {
    -fx-padding: 10 12 12 12;
}

.users-dialog-section-title {
    -fx-font-size: 12px;
    -fx-font-weight: 900;
    -fx-text-fill: #1b2c44;
}

.users-dialog-section-subtitle {
    -fx-font-size: 10px;
    -fx-text-fill: #6a7d95;
}

.users-dialog-form {
    -fx-padding: 4 0 0 0;
    -fx-hgap: 8;
    -fx-vgap: 8;
}

.users-dialog-label {
    -fx-font-size: 11px;
    -fx-font-weight: 700;
    -fx-text-fill: #556a86;
    -fx-opacity: 0.98;
}

.users-dialog-field {
    -fx-background-color: linear-gradient(to bottom, rgba(255,255,255,0.99), rgba(250,252,255,0.98));
    -fx-border-color: #d6dfea;
    -fx-border-radius: 12;
    -fx-background-radius: 12;
    -fx-padding: 8 10 8 10;
    -fx-background-insets: 0;
    -fx-font-size: 11px;
}

.users-dialog-pane .text-field,
.users-dialog-pane .password-field,
.users-dialog-pane .combo-box-base,
.users-dialog-pane .date-picker {
    -fx-background-color: linear-gradient(to bottom, rgba(255,255,255,0.99), rgba(250,252,255,0.98));
    -fx-background-radius: 12;
    -fx-border-radius: 12;
